import math

def prime_factors(n):
    factors = {}
    # Check for factor 2
    while n % 2 == 0:
        factors[2] = factors.get(2, 0) + 1
        n = n // 2

    # Check for odd factors
    f = 3
    while f * f <= n:
        while n % f == 0:
            factors[f] = factors.get(f, 0) + 1
            n = n // f
        f += 2

    # If n is prime greater than 2
    if n > 1:
        factors[n] = factors.get(n, 0) + 1

    return factors

def main():
    N, P = map(int, input().split())

    # Special case: if P == 1, the only possibility is all numbers being 1
    if P == 1:
        print(1)
        return

    factors = prime_factors(P)
    ans = 1

    for prime, exp in factors.items():
        # Each of the N numbers can get at least exp // N copies of this prime factor
        if exp >= N:
            ans *= prime ** (exp // N)

    print(ans)

