    fac = [1] * (L + 1)
    inv_f = [1] * (L + 1)

    for i in range(1, L + 1):
        fac[i] = fac[i-1] * i % MOD

    inv_f[L] = pow(fac[L], MOD-2, MOD)
    for i in range(L, 0, -1):
        inv_f[i-1] = inv_f[i] * i % MOD

    def nCr(n, r):
        if r < 0 or r > n:
            return 0
        return fac[n] * inv_f[r] % MOD * inv_f[n - r] % MOD

    ans = 0
    # First inclusion-exclusion: over k, the number of elements that have a_i > floor(v_i/2)?
    for k in range(0, M+1):
        term = nCr(N, k) * nCr(3*M - k + N - 1, N - 1) % MOD
        if k % 2 == 0:
            ans = (ans + term) % MOD
        else:
            ans = (ans - term) % MOD

    # Second inclusion-exclusion: subtract the cases where for some i, a_i > v_i/2?
    # Actually, we need to subtract the cases where for some i, a_i > floor(v_i/2) + 1? 
    # The sample solution does:
    for k in range(0, M+1):
        term = nCr(N-1, k) * nCr(3*M - k - 2*M - 1 + N - 1, N - 1) % MOD
        term = term * N % MOD
        if k % 2 == 0:
            ans = (ans - term) % MOD
        else:
            ans = (ans + term) % MOD

    ans %= MOD
    if ans < 0:
        ans += MOD
    print(ans)

